callGraph.callee:
L.marker([lat, lng], { icon: customIcon })
      .addTo(map)
      .bindPopup(
        `<div style="color: #0f172a; font-family: sans-serif; font-weight: 800; font-size: 13px; text-transform: uppercase; padding: 4px 8px;">
          ${facilityName}
         </div>`,
        { closeButton: false }
      )
      .openPopup

(() => {
                const fullTitle = dict?.media_gallery?.title || "Doživite Atmosferu";
                const words = fullTitle.split(" ");
                if (words.length > 1) {
                  return (
                    <>
                      {words.slice(0, -1).join(" ")}{" "}
                      <span className="text-splash">{words[words.length - 1]}</span>
                    </>
                  );
                }
                return fullTitle;
              })
